# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
from botocore.exceptions import BotoCoreError, ClientError
import boto3
import requests
import urllib.parse as urlparse

def lambda_handler(event, context):
    # get viewer request data from event object
    viewer_request = event['Records'][0]['cf']['request']
    
    # fetch URLs from headers
    enrichment_urls = viewer_request.get('headers', {}).get('X-Enrich-URL', '').split(",")
    
    for url in enrichment_urls:
        try:
            response = requests.get(url)
            
            # Ensure HTTP status is 200 (OK), otherwise don't proceed with data merging
            if response.status_code == 200:
                content_type = response.headers['Content-Type']
                
                if 'json' in content_type:
                    enriched_data = json.loads(response.text)  # process JSON format
                    
                elif 'xml' in content_type or 'urlencoded' in content_type:  
                    enriched_data = response.text    # for XML and URL-encoded data, just pass the text response as is
                
                else:
                    print(f"Unsupported Content Type {content_type}")
                    
                viewer_request['body'] = json.dumps({**json.loads(viewer_request['body']), **enriched_data})  # merge the new data with existing request body
                
            else:
                print(f"Request to URL {url} returned HTTP status {response.status_code}")
        
        except requests.exceptions.RequestException as e:
            print("Error occurred when trying to fetch URL "+ url + ". Error = "+ str(e))
            
    return viewer_request   # send back modified request data